create table data (
	id INT,
	first_name VARCHAR(50) NOT NULL,
	last_name VARCHAR(50)NOT NULL,
	email VARCHAR(150),
	gender VARCHAR(50) NOT NULL,
	date_of_birth DATE NOT NULL,
	country_of_birth VARCHAR(50)
);
SET datestyle = 'MDY';

SELECT 1;


SELECT * FROM data; 

SELECT * FROM data ORDER BY country_of_birth;

SELECT * FROM data ORDER BY country_of_birth DESC;



